import { useState } from "react";
import { ethers } from "ethers";
import { FLOWARC_ADDRESS, PAYSLIP_NFT_ADDRESS, FLOWARC_ABI, PAYSLIP_ABI, USDC_ABI, USDC_ADDRESS } from "./contracts/abis";
import EmployerDashboard from "./components/EmployerDashboard";
import WorkerDashboard from "./components/WorkerDashboard";
import PayslipViewer from "./components/PayslipViewer";

const ARC_CHAIN_ID = "0x4cef52";

function App() {
  const [address, setAddress]           = useState("");
  const [flowArc, setFlowArc]           = useState(null);
  const [payslipNFT, setPayslipNFT]     = useState(null);
  const [usdc, setUsdc]                 = useState(null);
  const [isEmployer, setIsEmployer]     = useState(false);
  const [activeTab, setActiveTab]       = useState("employer");
  const [loading, setLoading]           = useState(false);
  const [notification, setNotification] = useState(null);

  const notify = (msg, type = "success") => {
    setNotification({ msg, type });
    setTimeout(() => setNotification(null), 4000);
  };

  const switchToArc = async () => {
    try {
      await window.ethereum.request({ method: "wallet_switchEthereumChain", params: [{ chainId: ARC_CHAIN_ID }] });
      return true;
    } catch (switchError) {
      if (switchError.code === 4902) {
        try {
          await window.ethereum.request({ method: "wallet_addEthereumChain", params: [{ chainId: ARC_CHAIN_ID, chainName: "Arc Testnet", rpcUrls: ["https://rpc.testnet.arc.network"], nativeCurrency: { name: "USDC", symbol: "USDC", decimals: 18 }, blockExplorerUrls: ["https://testnet.arcscan.app"] }] });
          return true;
        } catch (e) { notify("Failed to add Arc Testnet", "error"); return false; }
      }
      notify("Please switch to Arc Testnet", "error"); return false;
    }
  };

  const connectWallet = async () => {
    if (!window.ethereum) return notify("Please install MetaMask!", "error");
    setLoading(true);
    try {
      await window.ethereum.request({ method: "eth_requestAccounts" });
      const switched = await switchToArc();
      if (!switched) { setLoading(false); return; }
      const _provider = new ethers.providers.Web3Provider(window.ethereum);
      const _signer   = _provider.getSigner();
      const _address  = await _signer.getAddress();
      const _flowArc    = new ethers.Contract(FLOWARC_ADDRESS, FLOWARC_ABI, _signer);
      const _payslipNFT = new ethers.Contract(PAYSLIP_NFT_ADDRESS, PAYSLIP_ABI, _signer);
      const _usdc       = new ethers.Contract(USDC_ADDRESS, USDC_ABI, _signer);
      const employerData = await _flowArc.employers(_address);
      setIsEmployer(employerData.registered);
      setAddress(_address);
      setFlowArc(_flowArc);
      setPayslipNFT(_payslipNFT);
      setUsdc(_usdc);
      notify("Wallet connected!");
    } catch (e) { notify(e.message, "error"); }
    setLoading(false);
  };

  const shortAddress = (addr) => addr ? `${addr.slice(0, 6)}...${addr.slice(-4)}` : "";

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Syne:wght@400;600;700;800&family=DM+Sans:wght@300;400;500;600&display=swap');
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        :root {
          --gold: #F0C060; --gold-light: #F7D98A; --gold-dim: rgba(240,192,96,0.15);
          --dark: #080810; --dark2: #0E0E1A; --dark3: #141428;
          --border: rgba(240,192,96,0.18); --text: #E8E4F0; --muted: #7A758E;
          --success: #4ADE80; --danger: #F87171; --radius: 16px;
        }
        body { background: var(--dark); color: var(--text); font-family: 'DM Sans', sans-serif; min-height: 100vh; }
        .app-bg { position: fixed; inset: 0; z-index: 0; pointer-events: none;
          background: radial-gradient(ellipse 80% 60% at 10% 0%, rgba(240,192,96,0.07) 0%, transparent 60%),
            radial-gradient(ellipse 60% 50% at 90% 100%, rgba(120,80,200,0.08) 0%, transparent 60%),
            linear-gradient(160deg, #080810 0%, #0E0E1A 50%, #080814 100%); }
        .grid-lines { position: fixed; inset: 0; z-index: 0; pointer-events: none;
          background-image: linear-gradient(rgba(240,192,96,0.03) 1px, transparent 1px), linear-gradient(90deg, rgba(240,192,96,0.03) 1px, transparent 1px);
          background-size: 60px 60px; }
        .app-wrap { position: relative; z-index: 1; min-height: 100vh; }
        .header { display: flex; align-items: center; justify-content: space-between; padding: 22px 48px;
          border-bottom: 1px solid var(--border); backdrop-filter: blur(20px);
          background: rgba(8,8,16,0.7); position: sticky; top: 0; z-index: 100; }
        .logo { display: flex; align-items: center; gap: 12px; }
        .logo-icon { width: 38px; height: 38px; border-radius: 10px;
          background: linear-gradient(135deg, var(--gold), #C07820); display: flex; align-items: center;
          justify-content: center; font-size: 18px; font-weight: 800; box-shadow: 0 0 20px rgba(240,192,96,0.3); }
        .logo-name { font-family: 'Syne', sans-serif; font-size: 22px; font-weight: 800;
          background: linear-gradient(90deg, var(--gold), var(--gold-light));
          -webkit-background-clip: text; -webkit-text-fill-color: transparent; letter-spacing: -0.5px; }
        .logo-badge { font-size: 10px; font-weight: 600; letter-spacing: 1.5px; color: var(--gold);
          background: var(--gold-dim); border: 1px solid var(--border); border-radius: 20px;
          padding: 3px 10px; text-transform: uppercase; }
        .wallet-pill { display: flex; align-items: center; gap: 10px; background: var(--dark3);
          border: 1px solid var(--border); border-radius: 50px; padding: 8px 18px; font-size: 13px; font-weight: 500; }
        .wallet-dot { width: 8px; height: 8px; border-radius: 50%; background: var(--success);
          box-shadow: 0 0 8px var(--success); animation: pulse 2s infinite; }
        @keyframes pulse { 0%,100%{opacity:1} 50%{opacity:0.5} }
        .connect-btn { background: linear-gradient(135deg, var(--gold), #C07820); color: #0a0a0a;
          border: none; border-radius: 50px; padding: 11px 28px; font-size: 14px; font-weight: 700;
          cursor: pointer; transition: all 0.2s; font-family: 'DM Sans', sans-serif;
          box-shadow: 0 4px 20px rgba(240,192,96,0.25); }
        .connect-btn:hover { transform: translateY(-1px); box-shadow: 0 6px 28px rgba(240,192,96,0.4); }
        .connect-btn:disabled { opacity: 0.6; cursor: not-allowed; transform: none; }
        .notif { position: fixed; top: 24px; right: 24px; z-index: 999; padding: 14px 24px;
          border-radius: 12px; font-size: 14px; font-weight: 600; backdrop-filter: blur(20px);
          animation: slideIn 0.3s ease; max-width: 360px; border: 1px solid rgba(255,255,255,0.1); }
        @keyframes slideIn { from{transform:translateX(40px);opacity:0} to{transform:translateX(0);opacity:1} }
        .notif-success { background: rgba(74,222,128,0.15); color: var(--success); border-color: rgba(74,222,128,0.3); }
        .notif-error { background: rgba(248,113,113,0.15); color: var(--danger); border-color: rgba(248,113,113,0.3); }
        .hero { min-height: calc(100vh - 83px); display: flex; flex-direction: column;
          align-items: center; justify-content: center; text-align: center; padding: 60px 24px; }
        .hero-eyebrow { font-size: 11px; font-weight: 700; letter-spacing: 3px; text-transform: uppercase;
          color: var(--gold); margin-bottom: 24px; display: flex; align-items: center; gap: 10px; }
        .hero-eyebrow::before, .hero-eyebrow::after { content: ''; flex: 1; max-width: 60px; height: 1px; background: var(--gold-dim); }
        .hero-title { font-family: 'Syne', sans-serif; font-size: clamp(42px, 7vw, 88px);
          font-weight: 800; line-height: 1.0; letter-spacing: -2px; margin-bottom: 28px; max-width: 900px; }
        .line2 { background: linear-gradient(90deg, var(--gold), var(--gold-light), #E0A040);
          -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
        .hero-sub { font-size: 18px; line-height: 1.7; color: var(--muted); max-width: 560px; margin-bottom: 48px; }
        .cta-primary { background: linear-gradient(135deg, var(--gold), #C07820); color: #0a0a0a;
          border: none; border-radius: 14px; padding: 16px 40px; font-size: 16px; font-weight: 700;
          cursor: pointer; transition: all 0.25s; font-family: 'DM Sans', sans-serif;
          box-shadow: 0 8px 32px rgba(240,192,96,0.3); margin-bottom: 60px; }
        .cta-primary:hover { transform: translateY(-2px); box-shadow: 0 12px 40px rgba(240,192,96,0.45); }
        .cta-primary:disabled { opacity: 0.6; cursor: not-allowed; transform: none; }
        .hero-stats { display: flex; border: 1px solid var(--border); border-radius: 20px; overflow: hidden;
          backdrop-filter: blur(10px); background: rgba(14,14,26,0.6); }
        .hero-stat { padding: 28px 40px; text-align: center; border-right: 1px solid var(--border); transition: background 0.2s; }
        .hero-stat:last-child { border-right: none; }
        .hero-stat:hover { background: var(--gold-dim); }
        .stat-icon { font-size: 24px; margin-bottom: 10px; }
        .stat-label { font-size: 12px; color: var(--muted); text-transform: uppercase; letter-spacing: 1px; font-weight: 600; }
        .dashboard { max-width: 1000px; margin: 0 auto; padding: 48px 24px; }
        .tabs-wrap { display: flex; gap: 4px; margin-bottom: 40px; background: var(--dark2);
          border: 1px solid var(--border); border-radius: 14px; padding: 5px; width: fit-content; }
        .tab-btn { padding: 10px 28px; border-radius: 10px; border: none; font-size: 14px; font-weight: 600;
          cursor: pointer; transition: all 0.2s; color: var(--muted); background: transparent;
          font-family: 'DM Sans', sans-serif; display: flex; align-items: center; gap: 8px; }
        .tab-btn:hover { color: var(--text); }
        .tab-btn.active { background: linear-gradient(135deg, var(--gold), #C07820); color: #0a0a0a; box-shadow: 0 4px 16px rgba(240,192,96,0.25); }
        .card { background: var(--dark2); border: 1px solid var(--border); border-radius: 20px; padding: 28px; margin-bottom: 20px; transition: border-color 0.2s; }
        .card:hover { border-color: rgba(240,192,96,0.3); }
        .card-title { font-family: 'Syne', sans-serif; font-size: 17px; font-weight: 700; margin-bottom: 6px; }
        .card-sub { font-size: 13px; color: var(--muted); margin-bottom: 24px; line-height: 1.5; }
        .balance-card { background: linear-gradient(135deg, #1A1428, #0E1020); border: 1px solid var(--border);
          border-radius: 24px; padding: 36px; margin-bottom: 24px;
          display: flex; justify-content: space-between; align-items: center; position: relative; overflow: hidden; }
        .balance-card::before { content: ''; position: absolute; top: -60px; right: -60px; width: 200px; height: 200px;
          border-radius: 50%; background: radial-gradient(circle, rgba(240,192,96,0.12), transparent 70%); }
        .bal-label { font-size: 12px; color: var(--muted); letter-spacing: 0.5px; margin-bottom: 8px; text-transform: uppercase; font-weight: 600; }
        .bal-value { font-family: 'Syne', sans-serif; font-size: 34px; font-weight: 800; }
        .bal-value .unit { font-size: 16px; color: var(--gold); font-weight: 600; margin-left: 6px; }
        .bal-divider { width: 1px; height: 60px; background: var(--border); }
        .inp { width: 100%; background: var(--dark); border: 1px solid var(--border); border-radius: 12px;
          padding: 14px 16px; color: var(--text); font-size: 14px; margin-bottom: 12px;
          font-family: 'DM Sans', sans-serif; transition: border-color 0.2s; outline: none; }
        .inp:focus { border-color: var(--gold); }
        .inp::placeholder { color: var(--muted); }
        .btn-gold { width: 100%; background: linear-gradient(135deg, var(--gold), #C07820); color: #0a0a0a;
          border: none; border-radius: 12px; padding: 14px; font-size: 14px; font-weight: 700;
          cursor: pointer; transition: all 0.2s; font-family: 'DM Sans', sans-serif; }
        .btn-gold:hover { transform: translateY(-1px); box-shadow: 0 6px 24px rgba(240,192,96,0.35); }
        .btn-gold:disabled { opacity: 0.5; cursor: not-allowed; transform: none; }
        .btn-danger { width: 100%; background: rgba(248,113,113,0.12); color: var(--danger);
          border: 1px solid rgba(248,113,113,0.3); border-radius: 12px; padding: 14px;
          font-size: 14px; font-weight: 700; cursor: pointer; transition: all 0.2s; font-family: 'DM Sans', sans-serif; }
        .btn-danger:hover { background: rgba(248,113,113,0.2); }
        .btn-danger:disabled { opacity: 0.5; cursor: not-allowed; }
        .two-col { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin-bottom: 20px; }
        .worker-row { display: flex; justify-content: space-between; align-items: center; padding: 18px;
          background: var(--dark); border: 1px solid var(--border); border-radius: 14px; margin-bottom: 10px; transition: border-color 0.2s; }
        .worker-row:hover { border-color: rgba(240,192,96,0.3); }
        .worker-name { font-family: 'Syne', sans-serif; font-size: 15px; font-weight: 700; margin-bottom: 4px; }
        .worker-addr { font-size: 12px; color: var(--muted); font-family: monospace; }
        .worker-salary { font-size: 13px; color: var(--gold); margin-top: 4px; font-weight: 600; }
        .worker-earned { font-size: 13px; color: var(--success); margin-bottom: 8px; font-weight: 600; }
        .badge-inactive { font-size: 10px; background: rgba(248,113,113,0.15); color: var(--danger);
          border: 1px solid rgba(248,113,113,0.3); padding: 2px 8px; border-radius: 20px; margin-left: 8px; font-weight: 600; }
        .btn-remove { background: rgba(248,113,113,0.1); color: var(--danger); border: 1px solid rgba(248,113,113,0.25);
          border-radius: 8px; padding: 7px 16px; font-size: 12px; font-weight: 600; cursor: pointer; transition: all 0.2s; font-family: 'DM Sans', sans-serif; }
        .btn-remove:hover { background: rgba(248,113,113,0.2); }
        .earned-card { display: flex; justify-content: space-between; align-items: center;
          background: linear-gradient(135deg, #0A1A14, #0E1820); border: 1px solid rgba(74,222,128,0.2);
          border-radius: 24px; padding: 36px; margin-bottom: 24px; position: relative; overflow: hidden; }
        .earned-card::before { content: ''; position: absolute; bottom: -40px; left: -40px; width: 160px; height: 160px;
          border-radius: 50%; background: radial-gradient(circle, rgba(74,222,128,0.08), transparent 70%); }
        .earned-label { font-size: 12px; color: var(--muted); text-transform: uppercase; letter-spacing: 1px; margin-bottom: 10px; font-weight: 600; }
        .earned-amount { font-family: 'Syne', sans-serif; font-size: 42px; font-weight: 800; color: var(--success); line-height: 1; }
        .earned-unit { font-size: 18px; color: var(--muted); margin-left: 6px; font-weight: 400; }
        .streaming-badge { display: inline-flex; align-items: center; gap: 6px; margin-top: 10px; font-size: 12px; color: var(--success); font-weight: 600; }
        .streaming-dot { width: 6px; height: 6px; border-radius: 50%; background: var(--success); animation: pulse 1.5s infinite; }
        .btn-claim { background: linear-gradient(135deg, var(--success), #16A34A); color: #fff; border: none;
          border-radius: 14px; padding: 18px 36px; font-size: 16px; font-weight: 700; cursor: pointer;
          transition: all 0.25s; font-family: 'DM Sans', sans-serif; box-shadow: 0 8px 28px rgba(74,222,128,0.25); white-space: nowrap; }
        .btn-claim:hover { transform: translateY(-2px); box-shadow: 0 12px 36px rgba(74,222,128,0.4); }
        .btn-claim:disabled { opacity: 0.4; cursor: not-allowed; transform: none; }
        .info-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 14px; margin-bottom: 20px; }
        .info-card { background: var(--dark); border: 1px solid var(--border); border-radius: 14px; padding: 18px; transition: border-color 0.2s; }
        .info-card:hover { border-color: rgba(240,192,96,0.3); }
        .info-label { font-size: 11px; color: var(--muted); text-transform: uppercase; letter-spacing: 1px; margin-bottom: 8px; font-weight: 600; }
        .info-value { font-size: 15px; font-weight: 600; }
        .payslip-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; }
        .payslip-card { background: var(--dark2); border: 1px solid var(--border); border-radius: 20px; overflow: hidden; transition: all 0.25s; }
        .payslip-card:hover { transform: translateY(-3px); border-color: rgba(240,192,96,0.4); box-shadow: 0 12px 40px rgba(0,0,0,0.4); }
        .payslip-header { background: linear-gradient(135deg, #1A1428, #12102A); padding: 20px 24px;
          display: flex; justify-content: space-between; align-items: center; border-bottom: 1px solid var(--border); }
        .nft-badge { font-family: 'Syne', sans-serif; font-size: 13px; font-weight: 800; color: var(--gold);
          background: var(--gold-dim); border: 1px solid var(--border); padding: 4px 12px; border-radius: 20px; }
        .soul-badge { font-size: 11px; color: var(--muted); font-weight: 600; }
        .payslip-body { padding: 24px; }
        .payslip-company { font-family: 'Syne', sans-serif; font-size: 20px; font-weight: 700; margin-bottom: 20px; }
        .payslip-amount-box { background: var(--dark); border: 1px solid rgba(74,222,128,0.2); border-radius: 12px; padding: 18px; margin-bottom: 18px; }
        .payslip-amount-label { font-size: 11px; color: var(--muted); text-transform: uppercase; letter-spacing: 1px; margin-bottom: 6px; font-weight: 600; }
        .payslip-amount { font-family: 'Syne', sans-serif; font-size: 26px; font-weight: 800; color: var(--success); }
        .payslip-amount .unit { font-size: 13px; color: var(--muted); font-weight: 400; margin-left: 4px; }
        .detail-row { display: flex; justify-content: space-between; align-items: center; padding: 10px 0; border-bottom: 1px solid var(--border); }
        .detail-row:last-child { border-bottom: none; }
        .detail-key { font-size: 12px; color: var(--muted); font-weight: 600; }
        .detail-val { font-size: 13px; font-weight: 500; font-family: monospace; }
        .payslip-footer { display: flex; justify-content: space-between; align-items: center;
          padding: 14px 24px; border-top: 1px solid var(--border); background: var(--dark); }
        .verified-badge { font-size: 12px; color: var(--success); font-weight: 600; }
        .explorer-btn { font-size: 12px; color: var(--gold); background: none; border: none;
          cursor: pointer; font-weight: 600; font-family: 'DM Sans', sans-serif; transition: opacity 0.2s; }
        .explorer-btn:hover { opacity: 0.7; }
        .register-card { max-width: 480px; margin: 80px auto; background: var(--dark2); border: 1px solid var(--border);
          border-radius: 24px; padding: 48px; text-align: center; }
        .register-icon { font-size: 48px; margin-bottom: 20px; }
        .register-title { font-family: 'Syne', sans-serif; font-size: 26px; font-weight: 800; margin-bottom: 10px; }
        .register-sub { font-size: 14px; color: var(--muted); margin-bottom: 32px; line-height: 1.6; }
        .empty { text-align: center; padding: 48px 20px; color: var(--muted); font-size: 14px; }
        .stats-header { display: flex; gap: 16px; margin-bottom: 24px; }
        .stat-pill { flex: 1; background: var(--dark2); border: 1px solid var(--border); border-radius: 16px; padding: 20px 24px; text-align: center; }
        .stat-pill-num { font-family: 'Syne', sans-serif; font-size: 28px; font-weight: 800; color: var(--gold); }
        .stat-pill-label { font-size: 12px; color: var(--muted); margin-top: 4px; text-transform: uppercase; letter-spacing: 0.5px; font-weight: 600; }
        input[type=number]::-webkit-inner-spin-button { -webkit-appearance: none; }
      `}</style>

      <div className="app-bg" />
      <div className="grid-lines" />
      <div className="app-wrap">
        <header className="header">
          <div className="logo">
            <div className="logo-icon">⚡</div>
            <span className="logo-name">FlowArc</span>
            <span className="logo-badge">Testnet</span>
          </div>
          {address ? (
            <div className="wallet-pill">
              <div className="wallet-dot" />
              {shortAddress(address)}
            </div>
          ) : (
            <button className="connect-btn" onClick={connectWallet} disabled={loading}>
              {loading ? "Connecting..." : "Connect Wallet"}
            </button>
          )}
        </header>

        {notification && (
          <div className={`notif ${notification.type === "error" ? "notif-error" : "notif-success"}`}>
            {notification.type === "error" ? "⚠ " : "✓ "}{notification.msg}
          </div>
        )}

        {!address && (
          <section className="hero">
            <div className="hero-eyebrow">Built on Arc Testnet</div>
            <h1 className="hero-title">
              Payroll for the<br />
              <span className="line2">Onchain Economy</span>
            </h1>
            <p className="hero-sub">
              Stream USDC salaries per second, manage workers trustlessly, and mint soulbound payslip NFTs — all onchain.
            </p>
            <button className="cta-primary" onClick={connectWallet} disabled={loading}>
              {loading ? "Connecting..." : "Launch App →"}
            </button>
            <div className="hero-stats">
              <div className="hero-stat"><div className="stat-icon">⚡</div><div className="stat-label">Real-time Streaming</div></div>
              <div className="hero-stat"><div className="stat-icon">🎫</div><div className="stat-label">Payslip NFTs</div></div>
              <div className="hero-stat"><div className="stat-icon">🔒</div><div className="stat-label">Fully Onchain</div></div>
              <div className="hero-stat"><div className="stat-icon">💵</div><div className="stat-label">USDC Native</div></div>
            </div>
          </section>
        )}

        {address && (
          <main className="dashboard">
            <div className="tabs-wrap">
              {[{key:"employer",label:"Employer",icon:"👔"},{key:"worker",label:"Worker",icon:"👷"},{key:"payslips",label:"Payslips",icon:"🎫"}].map(t => (
                <button key={t.key} className={`tab-btn ${activeTab === t.key ? "active" : ""}`} onClick={() => setActiveTab(t.key)}>
                  {t.icon} {t.label}
                </button>
              ))}
            </div>
            {activeTab === "employer" && <EmployerDashboard flowArc={flowArc} usdc={usdc} address={address} isEmployer={isEmployer} setIsEmployer={setIsEmployer} notify={notify} />}
            {activeTab === "worker"   && <WorkerDashboard flowArc={flowArc} address={address} notify={notify} />}
            {activeTab === "payslips" && <PayslipViewer payslipNFT={payslipNFT} address={address} notify={notify} />}
          </main>
        )}
      </div>
    </>
  );
}

export default App;
